1	import { readFileSync } from "node:fs";
2	import { quote, claim, type Item, type Incident } from "./claim-office.js";
3	
4	const INSURANCE_VALUES: Record<string, number> = {
5	  sword: 1000,
6	  amulet: 600,
7	  staff: 800,
8	  potion: 400,
9	  rune: 250,
10	  moonstone: 250,
11	};
12	
13	const { customer, steps } = JSON.parse(readFileSync(0, "utf-8"));
14	
15	type Step =
16	  | { op: "quote"; items: Item[] }
17	  | { op: "claim"; policy: number; incident: Incident };
18	
19	const policies: Item[][] = [];
20	const remainingCaps = new Map<number, number>();
21	
22	function initialCap(items: Item[]): number {
23	  return items.reduce((sum, item) => sum + 2 * INSURANCE_VALUES[item.type], 0);
24	}
25	
26	function remainingCapFor(policyIndex: number): number {
27	  return remainingCaps.get(policyIndex) ?? initialCap(policies[policyIndex]);
28	}
29	
30	function failWith(message: string): never {
31	  process.stderr.write(`${message}\n`);
32	  process.exit(1);
33	}
34	
35	function assertKnownItemTypes(items: Item[]): void {
36	  for (const item of items) {
37	    if (!(item.type in INSURANCE_VALUES)) {
38	      failWith(`Unknown item type: ${item.type}`);
39	    }
40	  }
41	}
42	
43	function assertDamagesCoveredByPolicy(policyItems: Item[], incident: Incident): void {
44	  const policyTypes = new Set(policyItems.map((item) => item.type));
45	  for (const damage of incident.damages) {
46	    if (!policyTypes.has(damage.itemType)) {
47	      failWith(`Damage references item not in policy: ${damage.itemType}`);
48	    }
49	  }
50	}
51	
52	function assertNonNegativeDamageAmounts(incident: Incident): void {
53	  for (const damage of incident.damages) {
54	    if (damage.amount < 0) {
55	      failWith(`Damage amount must be non-negative: ${damage.amount}`);
56	    }
57	  }
58	}
59	
60	function assertDamageCountsWithinPolicy(policyItems: Item[], incident: Incident): void {
61	  const policyCounts = new Map<string, number>();
62	  for (const item of policyItems) {
63	    policyCounts.set(item.type, (policyCounts.get(item.type) ?? 0) + 1);
64	  }
65	  const damageCounts = new Map<string, number>();
66	  for (const damage of incident.damages) {
67	    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
68	  }
69	  for (const [itemType, count] of damageCounts) {
70	    if (count > (policyCounts.get(itemType) ?? 0)) {
71	      failWith(`Too many damages of type ${itemType} for policy`);
72	    }
73	  }
74	}
75	
76	const results = (steps as Step[]).map((step) => {
77	  if (step.op === "quote") {
78	    assertKnownItemTypes(step.items);
79	    const isFollowUp = policies.length > 0;
80	    policies.push(step.items);
81	    return { premium: quote(customer, step.items, { isFollowUp }) };
82	  }
83	  const policyItems = policies[step.policy];
84	  assertDamagesCoveredByPolicy(policyItems, step.incident);
85	  assertNonNegativeDamageAmounts(step.incident);
86	  assertDamageCountsWithinPolicy(policyItems, step.incident);
87	  const result = claim({ items: policyItems }, step.incident, remainingCapFor(step.policy));
88	  remainingCaps.set(step.policy, result.remainingCap);
89	  return result;
90	});
91	process.stdout.write(JSON.stringify({ results }));
