16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_RATE = 0.1;
18	const LOYALTY_DISCOUNT = 20;
19	const FOLLOW_UP_DISCOUNT = 15;
20	const LOYALTY_THRESHOLD_YEARS = 2;
21	const HIGH_ENCHANT_THRESHOLD = 5;
22	const HIGH_ENCHANT_SURCHARGE_RATE = 0.3;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	
25	const BASE_PRICES: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	const COMPONENT_UNIT_PRICE = 25;
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_PRICE = 60;
36	
37	// Base price for a group of items of the same component type (rune/moonstone).
38	// Exactly 3 of a kind forms a "block" priced at 60; otherwise 25 per item.
39	function componentGroupBase(count: number): number {
40	  return count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
41	}
42	
43	// Sum of base prices for all items, respecting per-type block discounts for components.
44	function policyBaseTotal(items: Item[]): number {
45	  const componentCounts: Record<string, number> = {};
46	  let nonComponentBase = 0;
47	  for (const item of items) {
48	    if (COMPONENT_TYPES.has(item.type)) {
49	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
50	    } else {
51	      nonComponentBase += BASE_PRICES[item.type];
52	    }
53	  }
54	  const componentBase = Object.values(componentCounts).reduce(
55	    (sum, count) => sum + componentGroupBase(count),
56	    0,
57	  );
58	  return nonComponentBase + componentBase;
59	}
60	
61	// Per-item surcharges (curse, high-enchantment) computed as a percentage of
62	// the item's individual base price. Components have no surcharges.
63	function itemSurcharges(item: Item): number {
64	  if (COMPONENT_TYPES.has(item.type)) return 0;
65	  const base = BASE_PRICES[item.type];
66	  let surcharge = 0;
67	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
68	  if ((item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD) {
69	    surcharge += base * HIGH_ENCHANT_SURCHARGE_RATE;
70	  }
71	  return surcharge;
72	}
